import React, { useEffect, useState } from "react";
import "./Internship.css";
import axios from "axios";

const Internship = ({ currentUser }) => {
  const [internships, setInternships] = useState([]);
  const [newInternship, setNewInternship] = useState({
    title: "",
    company: "",
    category: "",
    mode: "",
    location: "",
    description: "",
  });
  const [appliedInternships, setAppliedInternships] = useState([]);
  const [editingId, setEditingId] = useState(null);

  useEffect(() => {
    fetchInternships();
  }, []);

  const fetchInternships = async () => {
    try {
      const res = await axios.get("/api/internships");
      setInternships(res.data);
    } catch (err) {
      console.error(err);
    }
  };

  const handleApply = async (id) => {
    try {
      await axios.post(`/api/internships/${id}/apply`, {}, {
        headers: { Authorization: `Bearer ${currentUser.token}` },
      });
      setAppliedInternships([...appliedInternships, id]);
    } catch (err) {
      console.error("Apply error:", err);
    }
  };

  const handleChange = (e) => {
    setNewInternship({ ...newInternship, [e.target.name]: e.target.value });
  };

  const handleSave = async () => {
    try {
      if (editingId) {
        await axios.put(`/api/internships/${editingId}`, newInternship, {
          headers: { Authorization: `Bearer ${currentUser.token}` },
        });
        setEditingId(null);
      } else {
        await axios.post("/api/internships", newInternship, {
          headers: { Authorization: `Bearer ${currentUser.token}` },
        });
      }
      setNewInternship({
        title: "",
        company: "",
        category: "",
        mode: "",
        location: "",
        description: "",
      });
      fetchInternships();
    } catch (err) {
      console.error(err);
    }
  };

  const handleEdit = (internship) => {
    setNewInternship(internship);
    setEditingId(internship._id);
  };

  const handleDelete = async (id) => {
    try {
      await axios.delete(`/api/internships/${id}`, {
        headers: { Authorization: `Bearer ${currentUser.token}` },
      });
      fetchInternships();
    } catch (err) {
      console.error(err);
    }
  };

  return (
    <div className="internship-page">
      <h2>Internships</h2>

      {(currentUser.role === "admin" || currentUser.role === "hr") && (
        <div className="form-section">
          <h3>{editingId ? "Edit Internship" : "Post Internship"}</h3>
          <input name="title" placeholder="Title" onChange={handleChange} value={newInternship.title} />
          <input name="company" placeholder="Company" onChange={handleChange} value={newInternship.company} />
          <input name="category" placeholder="Category" onChange={handleChange} value={newInternship.category} />
          <input name="mode" placeholder="Mode (Remote/Offline)" onChange={handleChange} value={newInternship.mode} />
          <input name="location" placeholder="Location" onChange={handleChange} value={newInternship.location} />
          <textarea name="description" placeholder="Description" onChange={handleChange} value={newInternship.description} />
          <button onClick={handleSave}>{editingId ? "Update" : "Post"}</button>
        </div>
      )}

      <div className="internship-list">
        {internships.map((internship) => (
          <div key={internship._id} className="internship-card">
            <h4>{internship.title}</h4>
            <p><strong>Company:</strong> {internship.company}</p>
            <p><strong>Category:</strong> {internship.category}</p>
            <p><strong>Mode:</strong> {internship.mode}</p>
            <p><strong>Location:</strong> {internship.location}</p>
            <p>{internship.description}</p>

            {currentUser.role === "student" && (
              <button
                onClick={() => handleApply(internship._id)}
                disabled={appliedInternships.includes(internship._id)}
              >
                {appliedInternships.includes(internship._id) ? "Applied" : "Apply"}
              </button>
            )}

            {(currentUser.role === "admin" || currentUser.role === "hr") && (
              <div className="action-buttons">
                <button onClick={() => handleEdit(internship)}>Edit</button>
                <button onClick={() => handleDelete(internship._id)}>Delete</button>
              </div>
            )}
          </div>
        ))}
      </div>
    </div>
  );
};

export default Internship;
